import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface IndexData {
  name: string;
  currentValue: number;
  change: number;
  changePercent: number;
}

interface StockMarketData {
  indices: IndexData[];
}

export default function Widget() {
  const stockMarketData = response.data as StockMarketData;
  const { indices } = stockMarketData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: '#424242' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FFFFFF', mb: 1 }}>
            Market Overview
          </Typography>
          <Stack spacing={1.5}>
            {indices.map((index) => {
              const positiveChange = index.change >= 0;
              return (
                <Box key={index.name}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2" sx={{ color: '#BDBDBD', fontWeight: 600 }}>
                      {index.name}
                    </Typography>
                    <Stack direction="row" alignItems="center" spacing={0.5}>
                      {positiveChange ? (
                        <TrendingUp sx={{ fontSize: 16, color: '#4CAF50' }} />
                      ) : (
                        <TrendingDown sx={{ fontSize: 16, color: '#F44336' }} />
                      )}
                      <Typography variant="body2" sx={{ color: positiveChange ? '#4CAF50' : '#F44336' }}>
                        {positiveChange ? '+' : ''}
                        {index.change.toFixed(2)} ({index.changePercent.toFixed(2)}%)
                      </Typography>
                    </Stack>
                  </Stack>
                  <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                    {index.currentValue.toLocaleString()}
                  </Typography>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
